#include <stdio.h>
#include <stdlib.h>
#include <omp.h>

#ifdef RD_WG_SIZE_0_0
        #define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
        #define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
        #define BLOCK_SIZE RD_WG_SIZE
#else
        #define BLOCK_SIZE 16
#endif

void lud_diagonal_omp(float *m, int matrix_dim, int offset)
{
  int i, j;
  float shadow[BLOCK_SIZE][BLOCK_SIZE];

  int array_offset = offset*matrix_dim+offset;
  for(i=0; BLOCK_SIZE > i; i++){
    shadow[i][0]=m[array_offset+0];
    for(int t=1; t < BLOCK_SIZE; t++) {
      shadow[i][t]=m[array_offset+t];
    }
    array_offset = array_offset + (matrix_dim);
  }

  for(i=0; BLOCK_SIZE-1 > i; i++) {
    for(int t=i+1; t < BLOCK_SIZE; t++) {
      for(j=0; j < i; j++)
        shadow[t][i] -= shadow[t][j]*shadow[j][i];
      shadow[t][i] /= shadow[i][i];
    }

    for(int t=0; t < BLOCK_SIZE; t++) {
      for(j=0; j < i+1; j++)
        shadow[i+1][t] -= shadow[i+1][j]*shadow[j][t];
    }
  }

  array_offset = (offset+1)*matrix_dim+offset;
  for(i=1; BLOCK_SIZE > i; i++){
    m[array_offset+0]=shadow[i][0];
    for(int t=1; t < BLOCK_SIZE; t++) {
      m[array_offset+t]=shadow[i][t];
    }
    array_offset = array_offset + (matrix_dim);
  }
}

void lud_perimeter_omp(float *m, int matrix_dim, int offset, int num_blocks)
{
  float dia[BLOCK_SIZE][BLOCK_SIZE];
  float peri_row[BLOCK_SIZE][BLOCK_SIZE];
  float peri_col[BLOCK_SIZE][BLOCK_SIZE];

  int i, j, array_offset;
  int idx;

  for (idx=0; BLOCK_SIZE > idx; idx++){
    array_offset = offset*matrix_dim+offset;
    for (i=0; BLOCK_SIZE/2 > i; i++){
      dia[i][idx]=m[array_offset+idx];
      array_offset = array_offset + (matrix_dim);
    }

    array_offset = offset*matrix_dim+offset;
    for (i=0; BLOCK_SIZE > i; i++) {
      peri_row[i][idx]=m[array_offset+(1)*BLOCK_SIZE+idx];
      array_offset = array_offset + (matrix_dim);
    }
  }

  for (idx=0; BLOCK_SIZE > idx; idx++){
    array_offset = (offset+BLOCK_SIZE/2)*matrix_dim+offset;
    for (i=BLOCK_SIZE/2; BLOCK_SIZE > i; i++){
      dia[i][idx]=m[array_offset+idx];
      array_offset = array_offset + (matrix_dim);
    }

    array_offset = (offset+(1)*BLOCK_SIZE)*matrix_dim+offset;
    for (i=0; BLOCK_SIZE > i; i++) {
      peri_col[idx][i] = m[array_offset+idx];
      array_offset = array_offset + (matrix_dim);
    }
  }

  for(idx=0; BLOCK_SIZE > idx; idx++){
    for(i=1; BLOCK_SIZE > i; i++){
      for (j=0; i > j; j++)
        peri_row[i][idx]-=dia[i][j]*peri_row[j][idx];
    }
  }

  for(idx=0; BLOCK_SIZE > idx; idx++){
    for(i=0; BLOCK_SIZE > i; i++){
      for(j=0; i > j; j++)
        peri_col[idx][i]-=peri_col[idx][j]*dia[j][i];
      peri_col[idx][i] /= dia[i][i];
    }
  }

  int blk;
  #pragma omp parallel for
  for (blk=0; blk < num_blocks; blk++) {
    for(idx=0; BLOCK_SIZE > idx; idx++){
      array_offset = (offset+1)*matrix_dim+offset;
      for(i=1; BLOCK_SIZE > i; i++){
        m[array_offset+(blk+1)*BLOCK_SIZE+idx] = peri_row[i][idx];
        array_offset = array_offset + (matrix_dim);
      }
    }

    for(idx=0; BLOCK_SIZE > idx; idx++){
      array_offset = (offset+(blk+1)*BLOCK_SIZE)*matrix_dim+offset;
      for(i=0; BLOCK_SIZE > i; i++){
        m[array_offset+idx] =  peri_col[i][idx];
        array_offset = array_offset + (matrix_dim);
      }
    }
  }
}

void lud_internal_omp(float *m, int matrix_dim, int offset, int num_blocks)
{
  float peri_row[BLOCK_SIZE][BLOCK_SIZE];
  float peri_col[BLOCK_SIZE][BLOCK_SIZE];
  int i, j, k;
  float sum;

  int blk_row, blk_col;
  #pragma omp parallel for
  for (blk_row=0; blk_row < num_blocks; blk_row++) {
    for (blk_col=0; blk_col < num_blocks; blk_col++) {
      int global_row_id = offset + (blk_row+1)*BLOCK_SIZE;
      int global_col_id = offset + (blk_col+1)*BLOCK_SIZE;

      for (j=0; j < BLOCK_SIZE; j++) {
        for (i=0; i < BLOCK_SIZE; i++) {
          peri_row[j][i] = m[(offset+j)*matrix_dim+global_col_id+i];
          peri_col[j][i] = m[(global_row_id+j)*matrix_dim+offset+i];
        }
      }

      for (j=0; j < BLOCK_SIZE; j++) {
        for (i=0; i < BLOCK_SIZE; i++) {
          sum = 0;
          for (k=0; k < BLOCK_SIZE; k++)
            sum += peri_col[j][k] * peri_row[k][i];
          m[(global_row_id+j)*matrix_dim+global_col_id+i] -= sum;
        }
      }
    }
  }
}

void lud_omp(float *m, int matrix_dim)
{
  int i=0;
  int num_blocks;

  for (i=0; matrix_dim-BLOCK_SIZE > i; i += BLOCK_SIZE) {
      lud_diagonal_omp(m, matrix_dim, i);
      num_blocks = (matrix_dim-i)/BLOCK_SIZE-1;
      if (num_blocks > 0) {
        lud_perimeter_omp(m, matrix_dim, i, num_blocks);
        lud_internal_omp(m, matrix_dim, i, num_blocks);
      }
  }
  lud_diagonal_omp(m, matrix_dim, i);
}
